package com.company.supervision.application.messaging;import com.company.supervision.infrastructure.repository.messaging.WecomWebhookMapper;import com.company.supervision.infrastructure.security.SecretCipher;import org.springframework.boot.CommandLineRunner;import org.springframework.stereotype.Component;@Component public class LegacyWebhookEncryptor implements CommandLineRunner{private final WecomWebhookMapper m;private final SecretCipher c;public LegacyWebhookEncryptor(WecomWebhookMapper m,SecretCipher c){this.m=m;this.c=c;}public void run(String...args){for(var h:m.selectList(null))if(h.getWebhookCipher()!=null&&h.getWebhookCipher().startsWith("http")){h.setWebhookCipher(c.encrypt(h.getWebhookCipher()));m.updateById(h);}}}